# Helper function to compare VM properties
Function Compare-VmProperties {
    param(
        $CurrentVm,
        $DesiredProperties
    )

    $differences = @()

    if ($null -ne $DesiredProperties.cpu_count -and $CurrentVm.CPUCount -ne $DesiredProperties.cpu_count) {
        $differences += @{property = "CPUCount"; current = $CurrentVm.CPUCount; desired = $DesiredProperties.cpu_count}
    }

    if ($null -ne $DesiredProperties.memory_mb -and $CurrentVm.Memory -ne $DesiredProperties.memory_mb) {
        $differences += @{property = "Memory"; current = $CurrentVm.Memory; desired = $DesiredProperties.memory_mb}
    }

    if ($null -ne $DesiredProperties.dynamic_memory_enabled -and $CurrentVm.DynamicMemoryEnabled -ne $DesiredProperties.dynamic_memory_enabled) {
        $differences += @{property = "DynamicMemoryEnabled"; current = $CurrentVm.DynamicMemoryEnabled; desired = $DesiredProperties.dynamic_memory_enabled}
    }

    if ($null -ne $DesiredProperties.dynamic_memory_min_mb -and $CurrentVm.DynamicMemoryEnabled -and $CurrentVm.DynamicMemoryMinimumMB -ne $DesiredProperties.dynamic_memory_min_mb) {
        $differences += @{property = "DynamicMemoryMinimumMB"; current = $CurrentVm.DynamicMemoryMinimumMB; desired = $DesiredProperties.dynamic_memory_min_mb}
    }

    if ($null -ne $DesiredProperties.dynamic_memory_max_mb -and $CurrentVm.DynamicMemoryEnabled -and $CurrentVm.DynamicMemoryMaximumMB -ne $DesiredProperties.dynamic_memory_max_mb) {
        $differences += @{property = "DynamicMemoryMaximumMB"; current = $CurrentVm.DynamicMemoryMaximumMB; desired = $DesiredProperties.dynamic_memory_max_mb}
    }

    if ($null -ne $DesiredProperties.description -and $CurrentVm.Description -ne $DesiredProperties.description) {
        $differences += @{property = "Description"; current = $CurrentVm.Description; desired = $DesiredProperties.description}
    }

    if ($null -ne $DesiredProperties.start_action -and $CurrentVm.StartAction -ne $DesiredProperties.start_action) {
        $differences += @{property = "StartAction"; current = $CurrentVm.StartAction; desired = $DesiredProperties.start_action}
    }

    if ($null -ne $DesiredProperties.stop_action -and $CurrentVm.StopAction -ne $DesiredProperties.stop_action) {
        $differences += @{property = "StopAction"; current = $CurrentVm.StopAction; desired = $DesiredProperties.stop_action}
    }

    if ($null -ne $DesiredProperties.delay_start_seconds -and $CurrentVm.DelayStartSeconds -ne $DesiredProperties.delay_start_seconds) {
        $differences += @{property = "DelayStartSeconds"; current = $CurrentVm.DelayStartSeconds; desired = $DesiredProperties.delay_start_seconds}
    }

    if ($null -ne $DesiredProperties.checkpoint_type -and $CurrentVm.CheckpointType -ne $DesiredProperties.checkpoint_type) {
        $differences += @{property = "CheckpointType"; current = $CurrentVm.CheckpointType; desired = $DesiredProperties.checkpoint_type}
    }

    return $differences
}

# Helper function to build VM properties for diff mode
Function Get-VmPropertiesDict {
    param($Vm)

    return @{
        name = $Vm.Name
        status = $Vm.Status
        cpu_count = $Vm.CPUCount
        memory_mb = $Vm.Memory
        dynamic_memory_enabled = $Vm.DynamicMemoryEnabled
        dynamic_memory_min_mb = $Vm.DynamicMemoryMinimumMB
        dynamic_memory_max_mb = $Vm.DynamicMemoryMaximumMB
        description = $Vm.Description
        start_action = $Vm.StartAction
        stop_action = $Vm.StopAction
        delay_start_seconds = $Vm.DelayStartSeconds
        checkpoint_type = $Vm.CheckpointType
        vm_host = $Vm.HostName
        cloud = if ($Vm.Cloud) { $Vm.Cloud.Name } else { $null }
        generation = $Vm.Generation
    }
}

