                    $cloudObj = Get-SCCloud -VMMServer $vmmConnection -Name $cloud -ErrorAction Stop
                    $createParams.Cloud = $cloudObj
                } elseif ($vm_host) {
                    $vmHostObj = Get-SCVMHost -VMMServer $vmmConnection -ComputerName $vm_host -ErrorAction Stop
                    $createParams.VMHost = $vmHostObj
                } elseif ($host_group) {
                    $hostGroupObj = Get-SCVMHostGroup -VMMServer $vmmConnection -Name $host_group -ErrorAction Stop
                    $createParams.VMHostGroup = $hostGroupObj
                }

                # Storage path
                if ($path) {
                    $createParams.Path = $path
                }

                # Hardware configuration
                if ($cpu_count) {
                    $createParams.CPUCount = $cpu_count
                }

                if ($memory_mb) {
                    $createParams.MemoryMB = $memory_mb
                }

                if ($null -ne $dynamic_memory_enabled) {
                    $createParams.DynamicMemoryEnabled = $dynamic_memory_enabled
                }

                if ($dynamic_memory_min_mb) {
                    $createParams.DynamicMemoryMinimumMB = $dynamic_memory_min_mb
                }

                if ($dynamic_memory_max_mb) {
                    $createParams.DynamicMemoryMaximumMB = $dynamic_memory_max_mb
                }

                if ($hardware_profile) {
                    $hwProfile = Get-SCHardwareProfile -VMMServer $vmmConnection -Name $hardware_profile -ErrorAction Stop
                    $createParams.HardwareProfile = $hwProfile
                }

                if ($generation) {
                    $createParams.Generation = $generation
                }

                # Guest OS customization
                if ($computer_name) {
                    $createParams.ComputerName = $computer_name
                }

                if ($guest_os_profile) {
                    $guestProfile = Get-SCGuestOSProfile -VMMServer $vmmConnection -Name $guest_os_profile -ErrorAction Stop
                    $createParams.GuestOSProfile = $guestProfile
                }

                if ($full_name) {
                    $createParams.FullName = $full_name
                }

                if ($organization_name) {
                    $createParams.OrgName = $organization_name
                }

                if ($product_key) {
                    $createParams.ProductKey = $product_key
                }

                if ($time_zone) {
                    $createParams.TimeZone = $time_zone
                }

                if ($domain) {
                    $createParams.Domain = $domain
                }

                if ($workgroup) {
                    $createParams.Workgroup = $workgroup
                }

                if ($local_admin_password) {
                    $securePassword = ConvertTo-SecureString $local_admin_password -AsPlainText -Force
                    $createParams.LocalAdministratorPassword = $securePassword
                }

                # Network
                if ($vm_network) {
                    $vmNet = Get-SCVMNetwork -VMMServer $vmmConnection -Name $vm_network -ErrorAction Stop
                    $createParams.VMNetwork = $vmNet
                }

                # VM behavior
                if ($description) {
                    $createParams.Description = $description
                }

                if ($start_action) {
                    $createParams.StartAction = $start_action
                }

                if ($stop_action) {
                    $createParams.StopAction = $stop_action
                }

                if ($delay_start_seconds) {
                    $createParams.DelayStartSeconds = $delay_start_seconds
                }

                # Advanced features
                if ($null -ne $highly_available) {
                    $createParams.HighlyAvailable = $highly_available
                }

                if ($null -ne $enable_nested_virtualization) {
                    $createParams.EnableNestedVirtualization = $enable_nested_virtualization
                }

                if ($null -ne $secure_boot_enabled) {
                    $createParams.SecureBootEnabled = $secure_boot_enabled
                }

                if ($checkpoint_type) {
                    $createParams.CheckpointType = $checkpoint_type
                }

                # Start VM after creation
                if ($start_vm) {
                    $createParams.StartVM = $true
                }

                # Run asynchronously for better performance
                $createParams.RunAsynchronously = $true

                # PATTERN: Apply change (CREATE)
                $job = New-SCVirtualMachine @createParams

                # Wait for job completion
                do {
                    Start-Sleep -Seconds 2
                    $job = Get-SCJob -ID $job.ID
                } while ($job.Status -eq "Running")

                if ($job.Status -ne "Completed") {
                    $module.FailJson("Failed to create VM '$name'. Job status: $($job.Status). Error: $($job.ErrorInfo)")
                }

                # Retrieve the created VM
                $currentVm = Get-SCVirtualMachine -VMMServer $vmmConnection -Name $name -ErrorAction Stop

            } catch {
                $module.FailJson("Failed to create VM '$name'.", $_)
            }
        }

        $module.Result.changed = $true
        $module.Result.msg = "VM '$name' created successfully"

        if (-not $module.CheckMode) {
            $module.Result.vm = Get-VmPropertiesDict -Vm $currentVm
            $module.Diff.after = $module.Result.vm
        } else {
            $module.Diff.after = @{
                name = $name
                status = "PoweredOff"
            }
        }

    } else {
        # VM exists, check if update needed
        $module.Diff.before = Get-VmPropertiesDict -Vm $currentVm

        # Build desired properties for comparison
        $desiredProps = @{
            cpu_count = $cpu_count
            memory_mb = $memory_mb
            dynamic_memory_enabled = $dynamic_memory_enabled
            dynamic_memory_min_mb = $dynamic_memory_min_mb
            dynamic_memory_max_mb = $dynamic_memory_max_mb
            description = $description
            start_action = $start_action
            stop_action = $stop_action
            delay_start_seconds = $delay_start_seconds
            checkpoint_type = $checkpoint_type
        }

        # PATTERN: Compare current vs desired
        $differences = Compare-VmProperties -CurrentVm $currentVm -DesiredProperties $desiredProps

        if ($differences.Count -gt 0) {
            if (-not $module.CheckMode) {
                try {
                    # Build update parameters
                    $updateParams = @{
                        VM = $currentVm
                    }

                    foreach ($diff in $differences) {
                        switch ($diff.property) {
                            "CPUCount" { $updateParams.CPUCount = $diff.desired }
                            "Memory" { $updateParams.MemoryMB = $diff.desired }
                            "DynamicMemoryEnabled" { $updateParams.DynamicMemoryEnabled = $diff.desired }
                            "DynamicMemoryMinimumMB" { $updateParams.DynamicMemoryMinimumMB = $diff.desired }
                            "DynamicMemoryMaximumMB" { $updateParams.DynamicMemoryMaximumMB = $diff.desired }
                            "Description" { $updateParams.Description = $diff.desired }
                            "StartAction" { $updateParams.StartAction = $diff.desired }
                            "StopAction" { $updateParams.StopAction = $diff.desired }
                            "DelayStartSeconds" { $updateParams.DelayStartSeconds = $diff.desired }
                            "CheckpointType" { $updateParams.CheckpointType = $diff.desired }
                        }
                    }

                    # PATTERN: Apply change (UPDATE)
                    $updatedVm = Set-SCVirtualMachine @updateParams -ErrorAction Stop
                    $currentVm = $updatedVm

                } catch {
                    $module.FailJson("Failed to update VM '$name'.", $_)
                }
            }

            $module.Result.changed = $true
            $module.Result.msg = "VM '$name' updated successfully"
            $module.Result.differences = $differences

        } else {
            $module.Result.changed = $false
            $module.Result.msg = "VM '$name' already in desired state"
        }

        if (-not $module.CheckMode) {
            $module.Result.vm = Get-VmPropertiesDict -Vm $currentVm
            $module.Diff.after = $module.Result.vm
        } else {
            $module.Diff.after = $module.Diff.before
            if ($differences.Count -gt 0) {
                foreach ($diff in $differences) {
                    $propName = $diff.property.ToLower() -replace "mb$", "_mb"
                    $module.Diff.after[$propName] = $diff.desired
                }
            }
        }
    }

} else {
    # state == "absent"
    if ($null -ne $currentVm) {
        # VM exists, remove it
        $module.Diff.before = Get-VmPropertiesDict -Vm $currentVm
        $module.Diff.after = @{}

        if (-not $module.CheckMode) {
            try {
                # PATTERN: Apply change (DELETE)
                Remove-SCVirtualMachine -VM $currentVm -Force -ErrorAction Stop
            } catch {
                $module.FailJson("Failed to remove VM '$name'.", $_)
            }
        }

        $module.Result.changed = $true
        $module.Result.msg = "VM '$name' removed successfully"

    } else {
        $module.Result.changed = $false
        $module.Result.msg = "VM '$name' already absent"
        $module.Diff.before = @{}
        $module.Diff.after = @{}
    }
}

